  'GBPUSD,EURJPY,GBPJPY',
  'M15',
  '[{"key":"ASIAN_START","label":"Asian Start (UTC)","type":"int","default":0,"min":0,"max":6,"step":1,"tooltip":"Hour the Asian range tracking begins."},{"key":"ASIAN_END","label":"Asian End (UTC)","type":"int","default":6,"min":4,"max":10,"step":1,"tooltip":"Hour the Asian range tracking ends."},{"key":"BREAKOUT_BUFFER","label":"Breakout Buffer (pips)","type":"int","default":3,"min":0,"max":20,"step":1,"tooltip":"Extra pips beyond range for breakout confirmation."},{"key":"TIMEFRAME","label":"Timeframe","type":"enum","options":["PERIOD_M5","PERIOD_M15","PERIOD_H1"],"labels":["M5","M15","H1"],"default":"PERIOD_M15","tooltip":"Chart timeframe."},{"key":"MIN_RANGE_PIPS","label":"Min Range Size (pips)","type":"int","default":15,"min":0,"max":100,"step":5,"tooltip":"Skip breakout if Asian range is smaller than this."},{"key":"MAX_RANGE_PIPS","label":"Max Range Size (pips)","type":"int","default":80,"min":0,"max":300,"step":10,"tooltip":"Skip breakout if Asian range is larger than this. 0 = no limit."},{"key":"ADX_PERIOD","label":"ADX Period","type":"int","default":14,"min":0,"max":50,"step":1,"tooltip":"ADX period for trend strength filter. 0 = disabled."},{"key":"ADX_MIN_STRENGTH","label":"Min ADX Strength","type":"double","default":20,"min":10,"max":50,"step":1,"tooltip":"Minimum ADX value to allow entry."},{"key":"USE_ATR_STOPS","label":"Use ATR Stops","type":"bool","default":false,"tooltip":"Use ATR-based dynamic SL/TP instead of range-based stops."},{"key":"ATR_STOP_PERIOD","label":"ATR Stop Period","type":"int","default":14,"min":5,"max":50,"step":1,"tooltip":"ATR period for dynamic stops."},{"key":"ATR_SL_MULT","label":"ATR SL Multiplier","type":"double","default":1.5,"min":0.5,"max":5,"step":0.1,"tooltip":"ATR multiplier for stop loss."},{"key":"ATR_TP_MULT","label":"ATR TP Multiplier","type":"double","default":2,"min":0.5,"max":5,"step":0.1,"tooltip":"ATR multiplier for take profit."},{"key":"RISK_PERCENT","label":"Risk % per Trade","type":"double","default":0,"min":0,"max":5,"step":0.25,"tooltip":"Risk percentage of balance per trade. 0 = use fixed lot."},{"key":"LOT_SIZE","label":"Lot Size","type":"double","default":0.1,"min":0.01,"max":10,"step":0.01,"tooltip":"Trade volume in lots."},{"key":"SL_PIPS","label":"Stop Loss (pips)","type":"int","default":50,"min":5,"max":500,"step":5,"tooltip":"Stop loss distance in pips."},{"key":"TP_PIPS","label":"Take Profit (pips)","type":"int","default":100,"min":5,"max":1000,"step":5,"tooltip":"Take profit distance in pips."},{"key":"MAX_SPREAD","label":"Max Spread (points)","type":"int","default":30,"min":5,"max":100,"step":5,"tooltip":"Block entry if spread exceeds this."},{"key":"MULTI_SYMBOLS","label":"Multi-Asset Symbols","type":"string","default":"","tooltip":"Comma-separated symbols to trade (e.g. EURUSD,GBPUSD,USDJPY). Leave empty to trade chart symbol only."},{"key":"MAX_DAILY_LOSS","label":"Max Daily Loss %","type":"double","default":5,"min":1,"max":20,"step":0.5,"tooltip":"Stop trading after this % loss."},{"key":"CONSEC_LOSS_LIMIT","label":"Consecutive Loss Limit","type":"int","default":3,"min":1,"max":10,"step":1,"tooltip":"Pause after this many consecutive losses."},{"key":"BE_TRIGGER_RR","label":"Breakeven at R:R","type":"double","default":1,"min":0,"max":3,"step":0.1,"tooltip":"Move SL to breakeven at this R:R. 0 = disabled."},{"key":"TRAILING_STOP","label":"Trailing Stop (pips)","type":"int","default":0,"min":0,"max":200,"step":5,"tooltip":"Trailing stop distance. 0 = disabled."},{"key":"USE_SESSION_FILTER","label":"Session Filter","type":"bool","default":false,"tooltip":"Restrict trading to specific hours."},{"key":"SESSION_START","label":"Session Start (UTC)","type":"int","default":7,"min":0,"max":23,"step":1,"tooltip":"Trading starts at this hour."},{"key":"SESSION_END","label":"Session End (UTC)","type":"int","default":20,"min":0,"max":23,"step":1,"tooltip":"Trading stops at this hour."},{"key":"GMT_OFFSET","label":"Broker GMT Offset","type":"int","default":99,"min":-12,"max":99,"step":1,"tooltip":"Broker GMT offset. 99 = auto-detect."},{"key":"USE_ADAPTIVE","label":"Adaptive Mode","type":"bool","default":false,"tooltip":"Auto-adjust SL/TP/lot based on market regime (trending/ranging/volatile)."},{"key":"TREND_ADX_THRESH","label":"Trend ADX Threshold","type":"double","default":25,"min":15,"max":40,"step":1,"tooltip":"ADX above this = trending market (tighter SL, wider TP)."},{"key":"RANGE_ADX_THRESH","label":"Range ADX Threshold","type":"double","default":18,"min":10,"max":25,"step":1,"tooltip":"ADX below this = ranging market (wider SL, tighter TP)."},{"key":"VOLATILE_ATR_MULT","label":"Volatile ATR Multiplier","type":"double","default":1.8,"min":1.2,"max":3,"step":0.1,"tooltip":"ATR spike above this x average = volatile (wider SL, half lot)."}]',
  '//+------------------------------------------------------------------+
//| {{STRATEGY_NAME}} EA                                              |
//| Generated by TradeMetrics Pro Strategy Hub                        |
//+------------------------------------------------------------------+
#property copyright "TradeMetrics Pro"
#property version   "1.00"
#property strict

// ── Includes ────────────────────────────────────────────────────
#include <EdgeRelay_Common.mqh>
#include <EdgeRelay_Crypto.mqh>
#include <EdgeRelay_Http.mqh>
#include <EdgeRelay_Queue.mqh>
#include <EdgeRelay_JournalSync.mqh>
#include <EdgeRelay_JournalQueue.mqh>
#include <Trade\Trade.mqh>

// ── Strategy Parameters ─────────────────────────────────────────
input int              AsianStartHour  = {{ASIAN_START}};      // Asian Session Start (UTC)
input int              AsianEndHour    = {{ASIAN_END}};         // Asian Session End (UTC)
input int              BreakoutBuffer  = {{BREAKOUT_BUFFER}};   // Breakout Buffer (pips)
input ENUM_TIMEFRAMES  Timeframe       = {{TIMEFRAME}};         // Timeframe

// ── Range Size Filter ───────────────────────────────────────────
input int    MinRangePips     = {{MIN_RANGE_PIPS}};             // Min Range Size (pips)
input int    MaxRangePips     = {{MAX_RANGE_PIPS}};             // Max Range Size (pips)

// ── Strategy Filters ──────────────────────────────────────────
input int    ADXPeriod        = {{ADX_PERIOD}};                 // ADX Period (0=disabled)
input double ADXMinStrength   = {{ADX_MIN_STRENGTH}};           // Min ADX for Entry

// ── ATR Dynamic Stops ─────────────────────────────────────────
input bool   UseATRStops      = {{USE_ATR_STOPS}};              // Use ATR for SL/TP
input int    ATRStopPeriod    = {{ATR_STOP_PERIOD}};            // ATR Period for Stops
input double ATRSLMultiplier  = {{ATR_SL_MULT}};                // ATR SL Multiplier
input double ATRTPMultiplier  = {{ATR_TP_MULT}};                // ATR TP Multiplier

// ── Risk-Based Sizing ─────────────────────────────────────────
input double RiskPercent      = {{RISK_PERCENT}};               // Risk % of Balance (0=use fixed lot)

// ── Trade Management ────────────────────────────────────────────
input double LotSize            = {{LOT_SIZE}};              // Lot Size
input int    StopLossPips        = {{SL_PIPS}};               // Stop Loss (pips)
input int    TakeProfitPips      = {{TP_PIPS}};               // Take Profit (pips)
input int    MaxSpreadPoints     = {{MAX_SPREAD}};            // Max Spread (points)
input int    MagicNumber         = {{MAGIC_NUMBER}};          // Magic Number
input string MultiSymbols        = "{{MULTI_SYMBOLS}}";       // Multi-Asset Symbols (comma-separated, empty=chart symbol only)
input int    GMTOffset           = {{GMT_OFFSET}};            // Broker GMT Offset (99=auto-detect)

// ── Risk Management ─────────────────────────────────────────────
input double MaxDailyLossPercent   = {{MAX_DAILY_LOSS}};      // Max Daily Loss %
input int    ConsecutiveLossLimit  = {{CONSEC_LOSS_LIMIT}};   // Consecutive Loss Limit
input double BreakevenTriggerRR    = {{BE_TRIGGER_RR}};       // Breakeven at R:R
input double TrailingStopPips      = {{TRAILING_STOP}};       // Trailing Stop (pips)
input bool   UseSessionFilter      = {{USE_SESSION_FILTER}};  // Session Filter
input int    SessionStartHour      = {{SESSION_START}};       // Session Start (UTC)
input int    SessionEndHour        = {{SESSION_END}};         // Session End (UTC)

// ── Auto-Adaptive Mode ────────────────────────────────────
input bool   UseAdaptiveMode       = {{USE_ADAPTIVE}};        // Adaptive Mode (auto-adjust to market)
input double TrendADXThreshold     = {{TREND_ADX_THRESH}};    // ADX Threshold for Trending
input double RangeADXThreshold     = {{RANGE_ADX_THRESH}};    // ADX Threshold for Ranging
input double VolatileATRMult       = {{VOLATILE_ATR_MULT}};   // ATR Spike Multiplier for Volatile

// ── TradeMetrics Integration ────────────────────────────────────
input string AccountID        = "{{ACCOUNT_ID}}";
input string API_Key          = "{{API_KEY}}";
input string API_Secret       = "";                           // API Secret (enter manually)
input string API_Endpoint     = "https://edgerelay-signal-ingestion.ghwmelite.workers.dev";
input string JournalEndpoint  = "https://edgerelay-journal-sync.ghwmelite.workers.dev";
input bool   EnableJournal    = true;                         // Enable Journal Sync

// ── Shared Integration Block ────────────────────────────────────
{{TRADEMETRICS_BLOCK}}

// ── Multi-Asset Support ─────────────────────────────────────────
string g_symbols[];
int    g_symbolCount;
datetime g_lastBarTime[];

void InitSymbols()
{
   if(StringLen(MultiSymbols) == 0)
   { g_symbolCount = 1; ArrayResize(g_symbols, 1); g_symbols[0] = _Symbol; }
   else
   {
      string parts[];
      g_symbolCount = StringSplit(MultiSymbols, '','', parts);
      ArrayResize(g_symbols, g_symbolCount);
   ArrayResize(g_regimes, g_symbolCount);
      for(int i = 0; i < g_symbolCount; i++)
      { StringTrimLeft(parts[i]); StringTrimRight(parts[i]); g_symbols[i] = parts[i]; SymbolSelect(g_symbols[i], true); }
   }
   ArrayResize(g_lastBarTime, g_symbolCount);
   for(int i = 0; i < g_symbolCount; i++) g_lastBarTime[i] = 0;
}

int GetSymbolMagic(string symbol)
{ int hash = MagicNumber; for(int i = 0; i < StringLen(symbol); i++) hash = ((hash << 5) - hash + StringGetCharacter(symbol, i)) & 0x7FFFFFFF; return hash; }

double GetSymbolPip(string symbol)
{ int digits = (int)SymbolInfoInteger(symbol, SYMBOL_DIGITS); double point = SymbolInfoDouble(symbol, SYMBOL_POINT); return point * ((digits == 3 || digits == 5) ? 10 : 1); }

bool HasPositionFor(string symbol, ENUM_POSITION_TYPE direction, int magic)
{
   for(int i = PositionsTotal() - 1; i >= 0; i--)
   { ulong ticket = PositionGetTicket(i); if(ticket == 0) continue; if(PositionGetInteger(POSITION_MAGIC) != magic) continue;
     if(PositionGetString(POSITION_SYMBOL) != symbol) continue; if((ENUM_POSITION_TYPE)PositionGetInteger(POSITION_TYPE) == direction) return true; }
   return false;
}

void ClosePositionsFor(string symbol, ENUM_POSITION_TYPE direction, int magic)
{
   CTrade closeTrade; closeTrade.SetExpertMagicNumber(magic);
   for(int i = PositionsTotal() - 1; i >= 0; i--)
   { ulong ticket = PositionGetTicket(i); if(ticket == 0) continue; if(PositionGetInteger(POSITION_MAGIC) != magic) continue;
     if(PositionGetString(POSITION_SYMBOL) != symbol) continue; if((ENUM_POSITION_TYPE)PositionGetInteger(POSITION_TYPE) != direction) continue;
     double profit = PositionGetDouble(POSITION_PROFIT) + PositionGetDouble(POSITION_SWAP);
     if(closeTrade.PositionClose(ticket)) TM_OnTradeClosed(ticket, profit); }
}

bool IsNewBarForSymbol(int symIdx, string symbol)
{ datetime currentBar = iTime(symbol, Timeframe, 0); if(currentBar == g_lastBarTime[symIdx]) return false; g_lastBarTime[symIdx] = currentBar; return true; }

// ── Adaptive Mode ─────────────────────────────────────────
enum ENUM_MARKET_REGIME { REGIME_TRENDING, REGIME_RANGING, REGIME_VOLATILE, REGIME_NORMAL };
ENUM_MARKET_REGIME g_regimes[];

// ── Strategy Variables ──────────────────────────────────────────
// Per-symbol Asian range tracking
double   g_rangeHigh[];
double   g_rangeLow[];
bool     g_rangeReady[];
bool     g_tradedBuyToday[];
bool     g_tradedSellToday[];
datetime g_lastRangeDate[];
int      g_adxHandles[];
int      g_atrHandles[];
CTrade   g_trade;

//+------------------------------------------------------------------+
//| Calculate lot size based on risk percentage                       |
//+------------------------------------------------------------------+
double CalculateLotSize(double slPips, string symbol, double symPip)
  {
   if(RiskPercent <= 0 || slPips <= 0) return LotSize;
   double balance = AccountInfoDouble(ACCOUNT_BALANCE);
   double riskAmount = balance * RiskPercent / 100.0;
   double tickValue = SymbolInfoDouble(symbol, SYMBOL_TRADE_TICK_VALUE);
   double tickSize = SymbolInfoDouble(symbol, SYMBOL_TRADE_TICK_SIZE);
   if(tickValue <= 0 || tickSize <= 0) return LotSize;
   double lotSize = riskAmount / (slPips * symPip / tickSize * tickValue);
   double minLot = SymbolInfoDouble(symbol, SYMBOL_VOLUME_MIN);
   double maxLot = SymbolInfoDouble(symbol, SYMBOL_VOLUME_MAX);
   double lotStep = SymbolInfoDouble(symbol, SYMBOL_VOLUME_STEP);
   lotSize = MathMax(minLot, MathMin(maxLot, MathFloor(lotSize / lotStep) * lotStep));
   return lotSize;
  }

int OnInit()
  {
   InitSymbols();

   ArrayResize(g_adxHandles, g_symbolCount);
   ArrayResize(g_atrHandles, g_symbolCount);
   ArrayResize(g_rangeHigh, g_symbolCount);
   ArrayResize(g_rangeLow, g_symbolCount);
   ArrayResize(g_rangeReady, g_symbolCount);
   ArrayResize(g_tradedBuyToday, g_symbolCount);
   ArrayResize(g_tradedSellToday, g_symbolCount);
   ArrayResize(g_lastRangeDate, g_symbolCount);

   for(int i = 0; i < g_symbolCount; i++)
     {
      g_adxHandles[i] = INVALID_HANDLE;
      g_atrHandles[i] = INVALID_HANDLE;
      g_regimes[i] = REGIME_NORMAL;
      g_rangeHigh[i] = 0.0;
      g_rangeLow[i] = DBL_MAX;
      g_rangeReady[i] = false;
      g_tradedBuyToday[i] = false;
      g_tradedSellToday[i] = false;
      g_lastRangeDate[i] = 0;

      if(ADXPeriod > 0 || UseAdaptiveMode)
        {
         g_adxHandles[i] = iADX(g_symbols[i], Timeframe, (ADXPeriod > 0 ? ADXPeriod : 14));
         if(g_adxHandles[i] == INVALID_HANDLE)
           { PrintFormat("[AsianBreakout] Failed to create ADX handle for %s. Error: %d", g_symbols[i], GetLastError()); return INIT_FAILED; }
        }
      if(UseATRStops || UseAdaptiveMode)
        {
         g_atrHandles[i] = iATR(g_symbols[i], Timeframe, (UseATRStops ? ATRStopPeriod : 14));
         if(g_atrHandles[i] == INVALID_HANDLE)
           { PrintFormat("[AsianBreakout] Failed to create ATR handle for %s. Error: %d", g_symbols[i], GetLastError()); return INIT_FAILED; }
        }
     }

   g_trade.SetExpertMagicNumber(MagicNumber);
   g_trade.SetDeviationInPoints(10);
   g_trade.SetTypeFilling(ORDER_FILLING_IOC);
   return TM_OnInit();
  }

void OnDeinit(const int reason)
  {
   for(int i = 0; i < g_symbolCount; i++)
     {
      if(g_adxHandles[i] != INVALID_HANDLE) IndicatorRelease(g_adxHandles[i]);
      if(g_atrHandles[i] != INVALID_HANDLE) IndicatorRelease(g_atrHandles[i]);
     }
   TM_OnDeinit(reason);
  }

//+------------------------------------------------------------------+
//| Timer event handler                                               |
//+------------------------------------------------------------------+
void OnTimer()
  {
   TM_OnTimer();
  }

//+------------------------------------------------------------------+
//| Expert tick function                                              |
//+------------------------------------------------------------------+
void OnTick()
  {
   if(!TM_CanTrade()) return;

   MqlDateTime dt;
   TimeToStruct(TimeGMT(), dt);
   int hour = dt.hour;
   datetime today = StringToTime(TimeToString(TimeCurrent(), TIME_DATE));

   for(int si = 0; si < g_symbolCount; si++)
     {
      string sym = g_symbols[si];
      if(!IsNewBarForSymbol(si, sym)) continue;

      int magic = GetSymbolMagic(sym);
      double symPip = GetSymbolPip(sym);
      double symAsk = SymbolInfoDouble(sym, SYMBOL_ASK);
      double symBid = SymbolInfoDouble(sym, SYMBOL_BID);
      int symDigits = (int)SymbolInfoInteger(sym, SYMBOL_DIGITS);

      //--- Daily reset per symbol
      if(today != g_lastRangeDate[si])
        {
         g_lastRangeDate[si] = today;
         g_rangeHigh[si] = 0.0; g_rangeLow[si] = DBL_MAX;
         g_rangeReady[si] = false; g_tradedBuyToday[si] = false; g_tradedSellToday[si] = false;
        }

      bool inAsianSession = false;
      if(AsianStartHour < AsianEndHour)
         inAsianSession = (hour >= AsianStartHour && hour < AsianEndHour);
      else
         inAsianSession = (hour >= AsianStartHour || hour < AsianEndHour);

      if(inAsianSession)
        {
         double high = iHigh(sym, Timeframe, 1);
         double low  = iLow(sym, Timeframe, 1);
         if(high > g_rangeHigh[si]) g_rangeHigh[si] = high;
         if(low  < g_rangeLow[si])  g_rangeLow[si]  = low;
         g_rangeReady[si] = false;
         continue;
        }

      if(g_rangeHigh[si] > 0.0 && g_rangeLow[si] < DBL_MAX)
         g_rangeReady[si] = true;
      if(!g_rangeReady[si]) continue;

      double buffer = BreakoutBuffer * symPip;
      double rangeSizePips = (g_rangeHigh[si] - g_rangeLow[si]) / symPip;
      if(MinRangePips > 0 && rangeSizePips < MinRangePips) continue;
      if(MaxRangePips > 0 && rangeSizePips > MaxRangePips) continue;

      double close1 = iClose(sym, Timeframe, 1);
      double open1  = iOpen(sym, Timeframe, 1);
      double high1  = iHigh(sym, Timeframe, 1);
      double low1   = iLow(sym, Timeframe, 1);
      double body1  = MathAbs(close1 - open1);
      double range1 = high1 - low1;
      bool   momentumOK = (range1 > 0 && body1 / range1 > 0.60);

      double atrValue = 0.0;
      if(UseATRStops && g_atrHandles[si] != INVALID_HANDLE)
        { double atrArr[]; ArraySetAsSeries(atrArr, true); if(CopyBuffer(g_atrHandles[si], 0, 0, 2, atrArr) >= 2) atrValue = atrArr[1]; }


      //--- Detect market regime for adaptive mode
      double adaptiveSLMult  = 1.0;
      double adaptiveTPMult  = 1.0;
      double adaptiveLotMult = 1.0;

      if(UseAdaptiveMode)
        {
         double adxAdapt = 0.0;
         if(g_adxHandles[si] != INVALID_HANDLE)
           {
            double adxAdaptArr[];
            ArraySetAsSeries(adxAdaptArr, true);
            if(CopyBuffer(g_adxHandles[si], 0, 0, 2, adxAdaptArr) >= 2)
               adxAdapt = adxAdaptArr[1];
           }

         int adaptATRH = g_atrHandles[si];
         if(adaptATRH != INVALID_HANDLE)
           {
            double adaptATR[];
            ArraySetAsSeries(adaptATR, true);
            if(CopyBuffer(adaptATRH, 0, 1, 20, adaptATR) >= 20)
              {
               double currentATR = adaptATR[0];
               double avgATR = 0;
               for(int ai = 1; ai < 20; ai++) avgATR += adaptATR[ai];
               avgATR /= 19.0;

               if(currentATR > avgATR * VolatileATRMult)
                  g_regimes[si] = REGIME_VOLATILE;
               else if(adxAdapt > TrendADXThreshold)
                  g_regimes[si] = REGIME_TRENDING;
               else if(adxAdapt < RangeADXThreshold)
                  g_regimes[si] = REGIME_RANGING;
               else
                  g_regimes[si] = REGIME_NORMAL;
              }
           }

         switch(g_regimes[si])
           {
            case REGIME_TRENDING:  adaptiveSLMult = 0.8; adaptiveTPMult = 1.5; adaptiveLotMult = 1.0; break;
            case REGIME_RANGING:   adaptiveSLMult = 1.2; adaptiveTPMult = 0.7; adaptiveLotMult = 0.8; break;
            case REGIME_VOLATILE:  adaptiveSLMult = 1.5; adaptiveTPMult = 1.3; adaptiveLotMult = 0.5; break;
            default: break;
           }
        }
      bool buySignal  = (close1 > g_rangeHigh[si] + buffer && momentumOK && !g_tradedBuyToday[si]);
      bool sellSignal = (close1 < g_rangeLow[si] - buffer && momentumOK && !g_tradedSellToday[si]);

      if((buySignal || sellSignal) && ADXPeriod > 0 && g_adxHandles[si] != INVALID_HANDLE)
        {
         double adxVal[]; ArraySetAsSeries(adxVal, true);
         if(CopyBuffer(g_adxHandles[si], 0, 0, 2, adxVal) >= 2)
           { if(adxVal[1] < ADXMinStrength) { buySignal = false; sellSignal = false; } }
         else { buySignal = false; sellSignal = false; }
        }

      if(buySignal)
        {
         ClosePositionsFor(sym, POSITION_TYPE_SELL, magic);
         if(!HasPositionFor(sym, POSITION_TYPE_BUY, magic))
           {
            double slDist = 0.0, tpDist = 0.0;
            if(UseATRStops && atrValue > 0)
              { slDist = atrValue * ATRSLMultiplier; tpDist = atrValue * ATRTPMultiplier; }
            else
              {
               slDist = symAsk - g_rangeLow[si];
               tpDist = (TakeProfitPips > 0) ? TakeProfitPips * symPip : slDist * 2.0;
               if(StopLossPips > 0) { double userSlDist = StopLossPips * symPip; if(userSlDist < slDist) slDist = userSlDist; }
              }
            slDist *= adaptiveSLMult;
            tpDist *= adaptiveTPMult;

            double sl = (slDist > 0) ? NormalizeDouble(symAsk - slDist, symDigits) : 0.0;
            double tp = (tpDist > 0) ? NormalizeDouble(symAsk + tpDist, symDigits) : 0.0;
            double slPips = (slDist > 0) ? slDist / symPip : 0.0;
            double lot = CalculateLotSize(slPips, sym, symPip) * adaptiveLotMult;

            g_trade.SetExpertMagicNumber(magic);
            if(g_trade.Buy(lot, sym, symAsk, sl, tp, StringFormat("TM:%s|SIG:%s", "AsianBO", "BUY_BREAKOUT")))
              { ulong ticket = g_trade.ResultOrder(); if(ticket > 0) { TM_OnTradeOpened(ticket, sym, "buy", lot, symAsk, sl, tp); g_tradedBuyToday[si] = true; } }
           }
        }

      if(sellSignal)
        {
         ClosePositionsFor(sym, POSITION_TYPE_BUY, magic);
         if(!HasPositionFor(sym, POSITION_TYPE_SELL, magic))
           {
            double slDist = 0.0, tpDist = 0.0;
            if(UseATRStops && atrValue > 0)
              { slDist = atrValue * ATRSLMultiplier; tpDist = atrValue * ATRTPMultiplier; }
            else
              {
               slDist = g_rangeHigh[si] - symBid;
               tpDist = (TakeProfitPips > 0) ? TakeProfitPips * symPip : slDist * 2.0;
               if(StopLossPips > 0) { double userSlDist = StopLossPips * symPip; if(userSlDist < slDist) slDist = userSlDist; }
              }
            slDist *= adaptiveSLMult;
            tpDist *= adaptiveTPMult;

            double sl = (slDist > 0) ? NormalizeDouble(symBid + slDist, symDigits) : 0.0;
            double tp = (tpDist > 0) ? NormalizeDouble(symBid - tpDist, symDigits) : 0.0;
            double slPips = (slDist > 0) ? slDist / symPip : 0.0;
            double lot = CalculateLotSize(slPips, sym, symPip) * adaptiveLotMult;

            g_trade.SetExpertMagicNumber(magic);
            if(g_trade.Sell(lot, sym, symBid, sl, tp, StringFormat("TM:%s|SIG:%s", "AsianBO", "SELL_BREAKOUT")))
              { ulong ticket = g_trade.ResultOrder(); if(ticket > 0) { TM_OnTradeOpened(ticket, sym, "sell", lot, symBid, sl, tp); g_tradedSellToday[si] = true; } }
           }
        }
     }

   TM_ManageOpenTrades();
  }

//+------------------------------------------------------------------+
//| Check if a position exists in the given direction                 |
//+------------------------------------------------------------------+
bool HasPositionByDirection(ENUM_POSITION_TYPE direction)
  {
   for(int i = PositionsTotal() - 1; i >= 0; i--)
     {
      ulong ticket = PositionGetTicket(i);
      if(ticket == 0) continue;
      if(PositionGetInteger(POSITION_MAGIC) != MagicNumber) continue;
      if(PositionGetString(POSITION_SYMBOL) != _Symbol) continue;
      if((ENUM_POSITION_TYPE)PositionGetInteger(POSITION_TYPE) == direction)
         return true;
     }
   return false;
  }

//+------------------------------------------------------------------+
//| Close all positions in the given direction                        |
//+------------------------------------------------------------------+
void ClosePositionsByDirection(ENUM_POSITION_TYPE direction)
  {
   for(int i = PositionsTotal() - 1; i >= 0; i--)
     {
      ulong ticket = PositionGetTicket(i);
      if(ticket == 0) continue;
      if(PositionGetInteger(POSITION_MAGIC) != MagicNumber) continue;
      if(PositionGetString(POSITION_SYMBOL) != _Symbol) continue;
      if((ENUM_POSITION_TYPE)PositionGetInteger(POSITION_TYPE) != direction) continue;

      double profit = PositionGetDouble(POSITION_PROFIT) + PositionGetDouble(POSITION_SWAP);

      if(g_trade.PositionClose(ticket))
         TM_OnTradeClosed(ticket, profit);
     }
  }
